SELECT "t5"."I_PRODUCT_NAME0" AS "PRODUCT_NAME", "t5"."S_STORE_NAME0" AS "STORE_NAME", "t5"."S_ZIP0" AS "STORE_ZIP", "t5"."CA_STREET_NUMBER1" AS "B_STREET_NUMBER", "t5"."CA_STREET_NAME1" AS "B_STREEN_NAME", "t5"."CA_CITY1" AS "B_CITY", "t5"."CA_ZIP1" AS "B_ZIP", "t5"."CA_STREET_NUMBER00" AS "C_STREET_NUMBER", "t5"."CA_STREET_NAME00" AS "C_STREET_NAME", "t5"."CA_CITY00" AS "C_CITY", "t5"."CA_ZIP00" AS "C_ZIP", "t5"."D_YEAR2" AS "SYEAR", "t5"."$f15" AS "CNT", "t5"."$f16" AS "S1", "t5"."$f17" AS "S2", "t5"."$f18" AS "S3", "t12"."$f16" AS "S116", "t12"."$f17" AS "S217", "t12"."$f18" AS "S318", "t12"."D_YEAR2" AS "SYEAR19", "t12"."$f15" AS "CNT20"
