GROUP BY "ITEM"."I_PRODUCT_NAME", "ITEM"."I_ITEM_SK", "STORE"."S_STORE_NAME", "STORE"."S_ZIP", "CUSTOMER_ADDRESS"."CA_STREET_NUMBER", "CUSTOMER_ADDRESS"."CA_STREET_NAME", "CUSTOMER_ADDRESS"."CA_CITY", "CUSTOMER_ADDRESS"."CA_ZIP", "CUSTOMER_ADDRESS0"."CA_STREET_NUMBER", "CUSTOMER_ADDRESS0"."CA_STREET_NAME", "CUSTOMER_ADDRESS0"."CA_CITY", "CUSTOMER_ADDRESS0"."CA_ZIP", "DATE_DIM"."D_YEAR", "DATE_DIM0"."D_YEAR", "DATE_DIM1"."D_YEAR") AS "t5",
(SELECT "ITEM0"."I_PRODUCT_NAME" AS "I_PRODUCT_NAME0", "ITEM0"."I_ITEM_SK" AS "I_ITEM_SK0", "STORE0"."S_STORE_NAME" AS "S_STORE_NAME0", "STORE0"."S_ZIP" AS "S_ZIP0", "CUSTOMER_ADDRESS1"."CA_STREET_NUMBER" AS "CA_STREET_NUMBER1", "CUSTOMER_ADDRESS1"."CA_STREET_NAME" AS "CA_STREET_NAME1", "CUSTOMER_ADDRESS1"."CA_CITY" AS "CA_CITY1", "CUSTOMER_ADDRESS1"."CA_ZIP" AS "CA_ZIP1", "CUSTOMER_ADDRESS2"."CA_STREET_NUMBER" AS "CA_STREET_NUMBER00", "CUSTOMER_ADDRESS2"."CA_STREET_NAME" AS "CA_STREET_NAME00", "CUSTOMER_ADDRESS2"."CA_CITY" AS "CA_CITY00", "CUSTOMER_ADDRESS2"."CA_ZIP" AS "CA_ZIP00", "DATE_DIM2"."D_YEAR" AS "D_YEAR2", "DATE_DIM3"."D_YEAR" AS "D_YEAR00", "DATE_DIM4"."D_YEAR" AS "D_YEAR10", COUNT(*) AS "$f15", SUM("STORE_SALES0"."SS_WHOLESALE_COST") AS "$f16", SUM("STORE_SALES0"."SS_LIST_PRICE") AS "$f17", SUM("STORE_SALES0"."SS_COUPON_AMT") AS "$f18"
FROM "tpcds"."STORE_SALES" AS "STORE_SALES0",
"tpcds"."STORE_RETURNS" AS "STORE_RETURNS0",
(SELECT "CATALOG_SALES0"."CS_ITEM_SK" AS "CS_ITEM_SK0", SUM("CATALOG_SALES0"."CS_EXT_LIST_PRICE") AS "$f1", SUM("CATALOG_RETURNS0"."CR_REFUNDED_CASH" + "CATALOG_RETURNS0"."CR_REVERSED_CHARGE" + "CATALOG_RETURNS0"."CR_STORE_CREDIT") AS "$f2"
