"tpcds"."DATE_DIM" AS "DATE_DIM2",
"tpcds"."DATE_DIM" AS "DATE_DIM3",
"tpcds"."DATE_DIM" AS "DATE_DIM4",
"tpcds"."STORE" AS "STORE0",
"tpcds"."CUSTOMER" AS "CUSTOMER0",
