WHERE "t5"."I_ITEM_SK0" = "t12"."I_ITEM_SK0" AND ("t5"."D_YEAR2" = 2000 AND "t12"."D_YEAR2" = 2000 + 1) AND ("t12"."$f15" <= "t5"."$f15" AND ("t5"."S_STORE_NAME0" = "t12"."S_STORE_NAME0" AND "t5"."S_ZIP0" = "t12"."S_ZIP0"))
